INSERT INTO public.drug_interactions (drug_a_id, drug_b_id, severity, mechanism, clinical_effect, management) VALUES
((SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), (SELECT id FROM public.drugs WHERE generic_name = 'Atorvastatin'), 'SEVERE', 'CYP3A4 inhibition', '4-5x statin levels → rhabdomyolysis', 'Avoid clarithromycin or use azithromycin'),
((SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), (SELECT id FROM public.drugs WHERE generic_name = 'Rosuvastatin'), 'MODERATE', 'Weak CYP3A4 interaction', 'Increased myopathy risk', 'Monitor for muscle pain'),
((SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), (SELECT id FROM public.drugs WHERE generic_name = 'Amlodipine'), 'MODERATE', 'CYP3A4 inhibition', 'Hypotension risk', 'Monitor blood pressure'),
((SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), (SELECT id FROM public.drugs WHERE generic_name = 'Warfarin'), 'SEVERE', 'CYP interaction', 'Increased INR → bleeding', 'Monitor INR closely'),
((SELECT id FROM public.drugs WHERE generic_name = 'Ciprofloxacin'), (SELECT id FROM public.drugs WHERE generic_name = 'Warfarin'), 'MODERATE', 'CYP1A2 inhibition', 'Increased INR', 'Monitor INR'),
((SELECT id FROM public.drugs WHERE generic_name = 'Fluoxetine'), (SELECT id FROM public.drugs WHERE generic_name = 'Tramadol'), 'SEVERE', 'Serotonin syndrome', 'Life-threatening serotonin syndrome', 'Avoid combination'),
((SELECT id FROM public.drugs WHERE generic_name = 'Escitalopram'), (SELECT id FROM public.drugs WHERE generic_name = 'Tramadol'), 'MODERATE', 'Serotonin risk', 'Monitor for serotonin syndrome', 'Use caution'),
((SELECT id FROM public.drugs WHERE generic_name = 'Diclofenac'), (SELECT id FROM public.drugs WHERE generic_name = 'Telmisartan'), 'SEVERE', 'Nephrotoxicity', 'Triple whammy with renal injury', 'Avoid together if possible'),
((SELECT id FROM public.drugs WHERE generic_name = 'Diclofenac'), (SELECT id FROM public.drugs WHERE generic_name = 'Ramipril'), 'SEVERE', 'Nephrotoxicity', 'Triple whammy with renal injury', 'Avoid together if possible'),
((SELECT id FROM public.drugs WHERE generic_name = 'Ibuprofen'), (SELECT id FROM public.drugs WHERE generic_name = 'Aspirin'), 'MODERATE', 'Reduced antiplatelet efficacy', 'Reduced protection against clotting', 'Avoid routine combination'),
((SELECT id FROM public.drugs WHERE generic_name = 'Warfarin'), (SELECT id FROM public.drugs WHERE generic_name = 'Aspirin'), 'SEVERE', 'Additive bleeding risk', 'Major hemorrhage', 'Avoid unless strict indication and monitoring'),
((SELECT id FROM public.drugs WHERE generic_name = 'Spironolactone'), (SELECT id FROM public.drugs WHERE generic_name = 'Ramipril'), 'MODERATE', 'Hyperkalemia', 'Cardiac arrest risk', 'Monitor potassium closely'),
((SELECT id FROM public.drugs WHERE generic_name = 'Spironolactone'), (SELECT id FROM public.drugs WHERE generic_name = 'Telmisartan'), 'MODERATE', 'Hyperkalemia', 'High potassium risk', 'Monitor potassium levels'),
((SELECT id FROM public.drugs WHERE generic_name = 'Digoxin'), (SELECT id FROM public.drugs WHERE generic_name = 'Amiodarone'), 'SEVERE', 'Reduced clearance', 'Digoxin toxicity', 'Reduce digoxin dose and monitor levels'),
((SELECT id FROM public.drugs WHERE generic_name = 'Metformin'), (SELECT id FROM public.drugs WHERE generic_name = 'Contrast dye'), 'MODERATE', 'Lactic acidosis risk', 'Contrast exposure elevates risk', 'Hold metformin around contrast'),
((SELECT id FROM public.drugs WHERE generic_name = 'Phenytoin'), (SELECT id FROM public.drugs WHERE generic_name = 'Sodium Valproate'), 'MODERATE', 'Altered metabolism', 'Variable phenytoin levels', 'Monitor drug levels'),
((SELECT id FROM public.drugs WHERE generic_name = 'Duloxetine'), (SELECT id FROM public.drugs WHERE generic_name = 'Tramadol'), 'SEVERE', 'Serotonin syndrome', 'Life-threatening serotonin syndrome', 'Avoid this combination'),
((SELECT id FROM public.drugs WHERE generic_name = 'Clopidogrel'), (SELECT id FROM public.drugs WHERE generic_name = 'Omeprazole'), 'MODERATE', 'CYP2C19 inhibition', 'Reduced antiplatelet effect', 'Use alternative PPI if possible'),
((SELECT id FROM public.drugs WHERE generic_name = 'Clopidogrel'), (SELECT id FROM public.drugs WHERE generic_name = 'Pantoprazole'), 'MINOR', 'Weak CYP2C19 effect', 'Possible reduced antiplatelet effect', 'Pantoprazole preferred over omeprazole'),
((SELECT id FROM public.drugs WHERE generic_name = 'Rivaroxaban'), (SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), 'SEVERE', 'P-gp and CYP3A4 inhibition', 'Increased bleeding risk', 'Avoid together or change agent'),
((SELECT id FROM public.drugs WHERE generic_name = 'Apixaban'), (SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), 'MODERATE', 'P-gp and CYP3A4 inhibition', 'Increased anticoagulant levels', 'Use caution or choose alternative'),
((SELECT id FROM public.drugs WHERE generic_name = 'Simvastatin'), (SELECT id FROM public.drugs WHERE generic_name = 'Amlodipine'), 'MODERATE', 'CYP3A4 inhibition', 'Limit simvastatin to 20 mg', 'Reduce simvastatin dose'),
((SELECT id FROM public.drugs WHERE generic_name = 'Methotrexate'), (SELECT id FROM public.drugs WHERE generic_name = 'Co-trimoxazole'), 'SEVERE', 'Antifolate interaction', 'Pancytopenia', 'Avoid combination'),
((SELECT id FROM public.drugs WHERE generic_name = 'Carbamazepine'), (SELECT id FROM public.drugs WHERE generic_name = 'Clarithromycin'), 'SEVERE', 'CYP3A4 inhibition', 'Carbamazepine toxicity', 'Avoid combination'),
((SELECT id FROM public.drugs WHERE generic_name = 'Theophylline'), (SELECT id FROM public.drugs WHERE generic_name = 'Ciprofloxacin'), 'SEVERE', 'CYP1A2 inhibition', 'Seizures', 'Avoid together'),
((SELECT id FROM public.drugs WHERE generic_name = 'Escitalopram'), (SELECT id FROM public.drugs WHERE generic_name = 'Ondansetron'), 'MODERATE', 'QT prolongation', 'Torsades risk', 'Use caution'),
((SELECT id FROM public.drugs WHERE generic_name = 'Metformin'), (SELECT id FROM public.drugs WHERE generic_name = 'Furosemide'), 'MINOR', 'Lactic acidosis risk in CKD', 'Small added risk', 'Monitor renal function'),
((SELECT id FROM public.drugs WHERE generic_name = 'Morphine'), (SELECT id FROM public.drugs WHERE generic_name = 'Escitalopram'), 'MINOR', 'CNS depression', 'Increased sedation', 'Monitor consciousness'),
((SELECT id FROM public.drugs WHERE generic_name = 'Pregabalin'), (SELECT id FROM public.drugs WHERE generic_name = 'Morphine'), 'MODERATE', 'CNS and respiratory depression', 'Sedation and respiratory depression', 'Reduce doses and monitor');
